const jwt = require('jsonwebtoken'); // Importing JSON Web Token module in NodeJS (npm install jsonwebtoken) 
module.exports = function(req, res, next){    // Middleware to verify JWTs with a given secret and options object  
        const token = req.header('x-auth-token');     // Extract the jwt from header of incoming request (Authorization: Bearer <jwt>) 
                                        
       if (!token){      // If there're no JWT, return a response with status code and message  
           res.status(401).json({msg:'No token auth authorised! Access denied.'})    
            next();    }         
        try { 
             const decoded = jwt.verify(token, 'jwtSecret');      // Verifying the JWT with a given secret (In production make sure to use environment variables or config files)  
              req.user = decoded.user;     // Adding user from payload into request for easy access in routes 
             next();    }          catch(e){        
               res.status(401).json({msg:'Token is not valid.'})     
            };};